// Create a new file named "asyncOperations.js"
const fs = require('fs');

function writeToFile(fileContent) {
  // Write the content to the file.
  fs.writeFileSync("asyncOperations.js", fileContent);
}

let fileContent = `
async function async1() {
  console.log('async1 start');
  await async2();
  console.log('async1 end')
}

async function async2() {
  console.log('async2');
}

console.log('script start');

setTimeout(function () {
  console.log('setTimeout');
}, 0);

async1();

new Promise(function (resolve) {
  console.log('promise1');
  resolve();
}).then(function () {
  console.log('promise2');
});

console.log('script end');
`;

writeToFile(fileContent);
```

This script will create a new file named "asyncOperations.js" in the same directory where you run it.

To get the path of this new file:

```bash
node asyncOperations.js
# Outputs:
/your/path/to/asyncOperations.js
```

Or use `path` module for absolute and relative paths.

```javascript
const path = require('path');

let filePath = path.resolve(__dirname, 'asyncOperations.js');
console.log(filePath);
```

